UPDATE system_config SET description = N'Số phút giữ ghế chờ thanh toán' WHERE config_key = 'booking.hold_minutes';
UPDATE system_config SET description = N'Số ghế tối đa 1 lần đặt' WHERE config_key = 'booking.max_seats';
UPDATE system_config SET description = N'Số booking tối đa 1 user/ngày — chống bot' WHERE config_key = 'booking.max_per_user_per_day';
UPDATE system_config SET description = N'Cho phép đặt vé tới X phút SAU khi suất bắt đầu' WHERE config_key = 'booking.cutoff_after_start_minutes';
UPDATE system_config SET description = N'Cho hủy vé trước X phút khi chiếu' WHERE config_key = 'booking.cancel_before_minutes';
UPDATE system_config SET description = N'Sau X phút từ giờ kết thúc, vé chưa check-in → NO_SHOW' WHERE config_key = 'booking.no_show_buffer_minutes';
UPDATE system_config SET description = N'Tối đa lần login fail / user / window' WHERE config_key = 'auth.login_max_attempts_per_user';
UPDATE system_config SET description = N'Tối đa lần login fail / IP / window' WHERE config_key = 'auth.login_max_attempts_per_ip';
UPDATE system_config SET description = N'Window rate limit login (phút)' WHERE config_key = 'auth.login_window_minutes';
UPDATE system_config SET description = N'Tối đa forgot-password / email / window' WHERE config_key = 'auth.forgot_password_max_per_email';
UPDATE system_config SET description = N'Tối đa forgot-password / IP / window' WHERE config_key = 'auth.forgot_password_max_per_ip';
UPDATE system_config SET description = N'Window rate limit forgot (phút)' WHERE config_key = 'auth.forgot_password_window_minutes';
