UPDATE system_config SET description = N'Window rate limit verify-token (phút)' WHERE config_key = 'auth.token_verify_window_minutes';
UPDATE system_config SET description = N'TTL reset password token (phút)' WHERE config_key = 'auth.password_reset_token_ttl_minutes';
UPDATE system_config SET description = N'Điểm tích mỗi 1.000đ chi tiêu' WHERE config_key = 'loyalty.points_per_1000_vnd';
UPDATE system_config SET description = N'Lifetime points để đạt SILVER' WHERE config_key = 'loyalty.silver_threshold';
UPDATE system_config SET description = N'Lifetime points để đạt GOLD' WHERE config_key = 'loyalty.gold_threshold';
UPDATE system_config SET description = N'Lifetime points để đạt PLATINUM' WHERE config_key = 'loyalty.platinum_threshold';
UPDATE system_config SET description = N'Default range Top movies/snacks (ngày)' WHERE config_key = 'statistics.dashboard_default_days';
UPDATE system_config SET description = N'TTL cache statistics (giây)' WHERE config_key = 'statistics.cache_ttl_seconds';

-- id_tracker.description cũng có khả năng bị tương tự (file 009 cùng pattern)
UPDATE id_tracker SET description = N'Booking code: CX-YYYYMMDD-NNN' WHERE entity_type = 'BOOKING';
UPDATE id_tracker SET description = N'Snack order code: SO-YYYYMMDD-NNN' WHERE entity_type = 'SNACK_ORDER';
UPDATE id_tracker SET description = N'Payment transaction code: PAY-YYYYMMDD-NNN' WHERE entity_type = 'PAYMENT';
